const res = $input.first().json;
if (!res.valid) {
  console.warn(`[license] INVALID: ${res.reason}`);
  // Don't crash — just stop workflows by not triggering anything
  return [{ json: { _license_valid: false, reason: res.reason } }];
}
console.log(`[license] Valid. Plan: ${res.plan}`);
return [{ json: { _license_valid: true, plan: res.plan, entitlements: res.entitlements } }];

const res   = $input.first().json;
const tenantId = $env.TENANT_ID;
const integrations = res.integrations || {};
const rows = [];

for (const [connector, health] of Object.entries(integrations)) {
  rows.push({
    tenant_id:    tenantId,
    connector,
    status:       health.status || 'unknown',
    latency_ms:   health.latency_ms || null,
    error_detail: health.error || null,
    checked_at:   new Date().toISOString()
  });
}
return rows.map(r => ({ json: r }));

