// Re-trigger delivery for failed items
const items = $input.all().map(i => i.json);
if (items.length === 0) return [{ json: { skipped: true } }];
console.log(`[retry] Re-attempting delivery for ${items.length} failed recommendations`);
return items.map(r => ({ json: { ...r, _retry: true } }));

